def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        priority = 45 + np.exp(-cap / 2) * 50
        if usage > 5:
            priority += 6000 * np.log1p(usage) ** 2
            if cap > 12:
                priority += 120 * np.tan(np.cbrt(cap)) + 55 * np.sin(cap * 1.7)
            else:
                priority -= 55 * usage ** 1.2
            for i in range(1, 7):
                factor = ((-1) ** i) * np.sin(usage * np.pi * i * 0.7) * 18 / i
                priority += factor
            if usage > 6:
                priority += (usage - 6) ** 4 * 120
        elif 4 < usage <= 5:
            delta = usage - 4
            priority += 2500 * delta ** 2.5 + 180 * np.cos(delta * 3)
            for j in range(1, 9):
                priority += np.tanh(usage * np.pi * j ** 1.2) * 22 / j
            if int(cap * 5) % 4 < 2:
                priority += 60 * np.sin(cap / 7)
            if usage < 4.6:
                priority -= 90 * np.exp(-4 * (usage - 4) ** 2)
        elif 3 < usage <= 4:
            priority += 2000 * (usage - 3) ** 2
            for k in range(1, 11):
                val = usage ** k
                if val < 0.7:
                    priority += val * 28 / k
                    if k % 4 == 0:
                        priority += 9 * k
                else:
                    priority += (1 - val / 1.5) * 18 / (k + 3)
                    if k == 7 and usage > 3.5:
                        priority += 25
            if cap % 2.7 < 0.6:
                priority += 45 * np.cos(cap * 2.5)
        elif 2 < usage <= 3:
            priority += 1100 * (usage - 2) ** 2.2
            for m in range(1, 14):
                pwr = usage ** m
                priority += (np.tanh(pwr * np.pi / 3) - 0.4) * 20 / m
                if usage < 0.05 * m:
                    priority -= 15 * m
            if cap < 0.1:
                priority += np.sqrt(cap) * 330
            elif cap < 1.1:
                priority += np.log1p(cap * 18) * 48
            else:
                priority += (cap % 7) * 32
        elif 1 < usage <= 2:
            priority += 1300 * (usage - 1) ** 1.5
            for n in range(1, 15):
                ratio_pow = usage ** n
                priority += (np.sin(ratio_pow * np.pi / 5) - 0.3) * 17 / n
                if usage < 0.06 * n:
                    priority -= 13 * n
            if cap % 1.7 < 0.35:
                priority += 29 * np.sin(cap * 2.2)
        elif 0.3 < usage <= 1:
            priority += 160 * (1 - usage) ** 1.5 + 110 * np.sqrt(usage)
            for o in range(1, 16):
                ratio_pow = usage ** o
                priority += (np.cos(ratio_pow * np.pi / 7) - 0.25) * 16 / o
                if usage < 0.03 * o:
                    priority -= 14 * o
            if cap < 0.05:
                priority += np.cbrt(cap) * 420
            elif cap < 1:
                priority += np.log1p(cap * 28) * 52
            else:
                priority += (cap % 9) * 33
        else:
            priority += 300 * (1 - usage) ** 4
            for p in range(1, 22):
                ratio_pow = usage ** p
                priority += (np.sin(ratio_pow * np.pi / 8) - 0.45) * 14 / p
                if usage < 0.02 * p:
                    priority -= 18 * p
            if cap < 0.02:
                priority += np.sqrt(cap) * 480
            elif cap < 1.3:
                priority += np.log1p(cap * 35) * 65
            else:
                priority += (cap % 10) * 40
        if cap < 0.03:
            priority += 90
            if usage > 0.85:
                priority += 110
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 22)
        elif cap < 1.1:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 40
            for r in range(1, 7):
                if int(cap * 1500) % (r + 6) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 55
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 110
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        proximity_score = 0
        if int(cap * 2700) % 21 == 0:
            proximity_score += 18
        if int(cap * 950) % 31 == 0:
            proximity_score -= 14
        if int(cap * 230) % 13 == 0:
            proximity_score += 16
        for u in range(1, 10):
            diff = abs(usage - u / 10)
            if diff < 0.025:
                proximity_score += 22 / u
            elif diff < 0.06:
                proximity_score += 12 / u
            else:
                proximity_score -= 6 / u
        for v in range(1, 9):
            mod_check = int(cap * 1900) % (v + 11)
            if mod_check == 0:
                proximity_score += v * 6
            elif mod_check == 4:
                proximity_score -= v * 5
        for w in range(1, 6):
            mod_check = int(usage * 1850) % (w + 7)
            if mod_check == 0:
                proximity_score += 12 * w
            elif mod_check == 4:
                proximity_score -= 9 * w
        priority += proximity_score
        if usage < 0.006:
            for x in range(1, 9):
                priority -= x * 11
                if x % 3 == 0:
                    priority += 6 * x
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
                if y == 4:
                    priority -= 20
        if cap > 3:
            if cap % 1 < 0.07:
                priority += 45
            if (int(cap * 2700) % 27 == 0) and (usage > 0.7):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.82):
                    priority -= 30
                elif (int(cap * 700) % (z + 11) == 6) and (usage > 0.42):
                    priority += 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
